// Task spectrum-tui-design-8-5 consolidation gate. loadingFg / loadingStyle were
// a third independent copy of the header.go leaf canvas-paint pair (headerStyle /
// headerCanvasBg). These tests prove the post-consolidation loading render is
// byte-identical to the PRE-refactor source:
//   - the helper-level probes pin loadingFg ‚Č° headerStyle and loadingStyle ‚Č°
//     headerCanvasBg (so the loading names delegate to the single header source,
//     never re-implement);
//   - preLoadingFg / preLoadingStyle reproduce the ORIGINAL inline-logic bodies
//     verbatim, and the loading-screen + loading-error full-screen goldens are
//     rendered from those originals, so any drift in the consolidated helpers'
//     style composition is caught byte-for-byte across light, dark, and NO_COLOR.
//
// No t.Parallel() ‚ÄĒ the shared canvas helpers make parallelism unsafe.

// preLoadingFg reproduces the ORIGINAL loadingFg inline logic verbatim ‚ÄĒ the
// golden the consolidation must preserve.
func preLoadingFg(fg theme.Token, mode theme.Mode, colourless bool) lipgloss.Style {
	if colourless {
		return lipgloss.NewStyle()
	}
	return lipgloss.NewStyle().
		Foreground(fg.ColorFor(mode)).
		Background(theme.MV.Canvas.ColorFor(mode))
}

// preLoadingStyle reproduces the ORIGINAL loadingStyle inline logic verbatim ‚ÄĒ
// the golden the consolidation must preserve.
func preLoadingStyle(mode theme.Mode, colourless bool) lipgloss.Style {
	if colourless {
		return lipgloss.NewStyle()
	}
	return lipgloss.NewStyle().Background(theme.MV.Canvas.ColorFor(mode))
}

// TestLoadingFg_DelegatesToHeaderStyle asserts the consolidated loadingFg renders
// a probe string byte-identically to headerStyle (the single header.go source)
// AND to the original inline loadingFg logic, across a representative token √ó both
// modes √ó colourless on/off. Pins that loadingFg no longer re-implements the leaf
// paint ‚ÄĒ it routes through the header helper.
func TestLoadingFg_DelegatesToHeaderStyle(t *testing.T) {
	tokens := []theme.Token{theme.MV.TextPrimary, theme.MV.AccentViolet, theme.MV.StateRed, theme.MV.TextFaint}
	for _, tok := range tokens {
		for _, mode := range []theme.Mode{theme.Dark, theme.Light} {
			for _, colourless := range []bool{false, true} {
				want := headerStyle(tok, mode, colourless).Render("probe")
				if got := loadingFg(tok, mode, colourless).Render("probe"); got != want {
					t.Errorf("loadingFg(tok=%s mode=%v col=%v) = %q, want headerStyle %q",
						tok.Name, mode, colourless, got, want)
				}
				pre := preLoadingFg(tok, mode, colourless).Render("probe")
				if want != pre {
					t.Errorf("headerStyle(tok=%s mode=%v col=%v) = %q drifts from pre-refactor loadingFg %q",
						tok.Name, mode, colourless, want, pre)
				}
			}
		}
	}
}

// TestLoadingStyle_DelegatesToHeaderCanvasBg asserts the consolidated loadingStyle
// renders a probe string byte-identically to headerCanvasBg (the single header.go
// source) AND to the original inline loadingStyle logic, across both modes √ó
// colourless on/off.
func TestLoadingStyle_DelegatesToHeaderCanvasBg(t *testing.T) {
	for _, mode := range []theme.Mode{theme.Dark, theme.Light} {
		for _, colourless := range []bool{false, true} {
			want := headerCanvasBg(mode, colourless).Render("  ")
			if got := loadingStyle(mode, colourless).Render("  "); got != want {
				t.Errorf("loadingStyle(mode=%v col=%v) = %q, want headerCanvasBg %q",
					mode, colourless, got, want)
			}
			pre := preLoadingStyle(mode, colourless).Render("  ")
			if want != pre {
				t.Errorf("headerCanvasBg(mode=%v col=%v) = %q drifts from pre-refactor loadingStyle %q",
					mode, colourless, want, pre)
			}
		}
	}
}

// TestLoadingScreen_ByteIdenticalAcrossConsolidation asserts the full loading
// screen render (both the normal mid-restore frame and the ¬ß10.5 error frame) is
// byte-for-byte identical across the consolidation, in light, dark, and NO_COLOR.
// The goldens in loadingScreenGoldens were CAPTURED from the PRE-refactor source
// (loadingFg/loadingStyle forked bodies, via a throwaway generator run ‚ÄĒ see the
// task notes), so a drift in canvas composition or the NO_COLOR carve-out after
// the consolidation is caught verbatim.
func TestLoadingScreen_ByteIdenticalAcrossConsolidation(t *testing.T) {
	const w, h = 80, 24
	frames := map[string]LoadingProgressView{
		"loading-screen": midRestoreProgress().View(),
		"loading-error":  errorFrameView(),
	}
	for name, view := range frames {
		for _, mode := range []theme.Mode{theme.Dark, theme.Light} {
			modeName := map[theme.Mode]string{theme.Dark: "dark", theme.Light: "light"}[mode]
			for _, colourless := range []bool{false, true} {
				want := loadingScreenGoldens[goldenKey{name, modeName, colourless}]
				got := renderLoadingScreen(view, w, h, mode, colourless)
				if got != want {
					t.Errorf("[%s %s col=%v] loading render drifted from pre-refactor golden\n got: %q\nwant: %q",
						name, modeName, colourless, ansi.Strip(got), ansi.Strip(want))
				}
			}
		}
	}
}

type goldenKey struct {
	frame      string
	mode       string
	colourless bool
}

